import style from './Blog.module.css'

const blogPosts = [
    {
        id: 1,
        title: 'Tips Membangun Website yang Modern dan Responsif',
        date: 'June 10, 2025',
        excerpt: 'Pelajari cara membuat website yang tidak hanya menarik secara visual, tetapi juga responsif dan cepat di semua perangkat.',
    },
    {
        id: 2,
        title: 'Kenapa Desain UI/UX Itu Penting?',
        date: 'June 5, 2025',
        excerpt: 'Desain UI/UX bukan sekadar soal estetika, tapi tentang bagaimana pengguna berinteraksi dengan produk digital.',
    },
    {
        id: 3,
        title: '5 Tools Gratis untuk Desain Web yang Keren',
        date: 'May 28, 2025',
        excerpt: 'Berikut 5 tools gratis yang wajib kamu coba untuk mempercepat dan memperindah proses desain website kamu.',
    },
];

function Blog() {
    return (
        <div className={style.blogpage}>

            <section className={style.blog_section}>
                <h1>Latest Blog Posts</h1>
                <div className={style.blog_list}>
                    {blogPosts.map((post) => (
                        <div key={post.id} className={style.blog_card}>
                            <h2>{post.title}</h2>
                            <p className={style.date}>{post.date}</p>
                            <p>{post.excerpt}</p>
                            <button>Read More</button>
                        </div>
                    ))}
                </div>
            </section>

            <footer className={style.footer}>
                &copy; 2025 MSHDQ. All rights reserved.
            </footer>
        </div>
    )
}

export default Blog;
